(function(){const e=document.getElementById("contributors");if(!e)return;const t=t=>{const n=document.getElementById("contributors");if(!n)return;for(const e of t){const t=`<div><a href="${e.html_url}"><img loading="lazy" src="${e.avatar_url}" width="60" height="60" alt="${e.login} avatar" title="${e.login}"></a></div>`;n.insertAdjacentHTML("beforeend",t)}},n=localStorage.getItem("contributors");if(n){const e=JSON.parse(n);if(e.timestamp>Date.now())return t(e.users)}fetch("https://api.github.com/orgs/Next2D/repos").then(e=>e.json()).then(e=>{Promise.all(e.map(e=>fetch(e.contributors_url).then(e=>e.json()))).then(e=>{const n=new Map;for(const t of e)if(Array.isArray(t))for(const e of t)n.has(e.id)||n.set(e.id,e);const o=[...n.values()];localStorage.setItem("contributors",JSON.stringify({timestamp:Date.now()+864e5,users:o})),t(o)})}).catch(()=>{})})();
